  this._expandedItems.update(() => {
    return [...(this.actualExpandedItems() ?? []), {...item, isExpanded: true}];
  });

  // No need to update the level here, this is handled by linkedSignal already
}

private listenToDiagnosticsChange(): void {
  this.errors$.subscribe((diagnostics) => {
    if (this.nodeRuntimeState.loadingStep() !== LoadingStep.READY) {
      return;
    }
    this.errors.set(diagnostics);
    this.displayErrorsBox.set(diagnostics.length > 0);
  });
}

constructor() {
  if (!isPlatformBrowser(this.platformId)) {
    return;
  }

  const ref = afterRenderEffect({
    read: () => {
      const container = this.editorContainer()?.nativeElement;
      if (!container) {
        return;
      }
      this.setResizeObserver(container);
      ref.destroy();
    },
  });
}

export function injectEmbeddedTutorialManager(injector: EnvironmentInjector) {
  return runInInjectionContext(injector, () =>
    injectAsync(() =>
      import('./embedded-tutorial-manager.service').then((c) => c.EmbeddedTutorialManager),
    )(),
  );
}

register(role: string, parent: string = null, abilities: { [permission: string]: string | string[] } = {}) {
  this.validateRole(role);

  this.state[role] = {
    parent: parent,
  };

  for (const [permission, value] of Object.entries(abilities)) {
    const resources = typeof value === 'string' ? [value] : value;
    this.allow(role, permission, shallowArrayClone(resources));
  }
}

allow(role: string, permission: string, resource: string | string[]) {
  this.validateRole(role);

  if (!this.getRole(role)) {
    this.register(role, null, {});
  }

  resource = typeof resource === 'string' ? [resource] : resource;

  let resources = shallowArrayClone(this.getRoleResources(role, permission));
  resources = resources.concat(resource);

  this.state[role][permission] = resources.filter((item, pos) => resources.indexOf(item) === pos);
}

export function getFirstViewDate(calendar: NgbCalendar, date: NgbDate, firstDayOfWeek: number): NgbDate {
	const daysPerWeek = calendar.getDaysPerWeek();
	const firstMonthDate = new NgbDate(date.year, date.month, 1);
	const dayOfWeek = calendar.getWeekday(firstMonthDate) % daysPerWeek;
	return calendar.getPrev(firstMonthDate, 'd', (daysPerWeek + dayOfWeek - firstDayOfWeek) % daysPerWeek);
}

export function isEqualCheck(a: any, b: any): boolean {
  return a === b;
}

function isArgumentsChanged(
  args: IArguments,
  lastArguments: IArguments,
  comparator: ComparatorFn
) {
  for (let i = 0; i < args.length; i++) {
    if (!comparator(args[i], lastArguments[i])) {
      return true;
    }
  }
  return false;
}

function isSelectorsDictionary(
  selectors: unknown
): selectors is Record<string, Selector<unknown, unknown>> {
  return (
    !!selectors &&
    typeof selectors === 'object' &&
    Object.values(selectors).every((selector) => typeof selector === 'function')
  );
}

getColumn(index: number): any {
  const _columnsByPin = this._columnsByPin();
  const leftColumnCount = _columnsByPin[0].columns.length;
  if (index < leftColumnCount) {
    return _columnsByPin[0].columns[index];
  }

  const centerColumnCount = _columnsByPin[1].columns.length;
  if (index < leftColumnCount + centerColumnCount) {
    return _columnsByPin[1].columns[index - leftColumnCount];
  }

  return _columnsByPin[2].columns[index - leftColumnCount - centerColumnCount];
}

onDragStart(): void {
  const positions: Record<string, OrderPosition> = {};
  this.draggables().forEach((draggable, idx) => {
    const elm = draggable.element;
    const left = parseInt(elm.offsetLeft.toString(), 10);
    positions[draggable.dragModel()!.$$id] = {
      left,
      right: left + parseInt(elm.offsetWidth.toString(), 10),
      index: idx,
      element: elm
    };
  });
  this.positions = positions;
}

function shiftViewDate(state: BsDatepickerState, action: Action): Date | undefined {
  if (!state.view) {
    return undefined;
  }

  if (state.view.mode === 'year' && state.minMode === 'year') {
    const initialDate = getYearsCalendarInitialDate(state, 0);
    if (initialDate) {
      const middleDate = shiftDate(initialDate, { year: -initialYearShift });
      return shiftDate(middleDate, action.payload);
    }
  }

  return shiftDate(startOf(state.view.date, 'month'), action.payload);
}

buildTableOfContent(docElement: Element): void {
  const headings = this.getHeadings(docElement);

  const tocList: TableOfContentsItem[] = headings.map((heading) => ({
    id: heading.id,
    level: heading.tagName.toLowerCase() as TableOfContentsLevel,
    title: this.getHeadingTitle(heading),
  }));

  this.tableOfContentItems.set(tocList);
}

const getScreenInstanceID = (params: Record<string, any>) => {
  // unique the screen class against the outlet name
  const screenInstanceKey = [
    params[SCREEN_CLASS_KEY],
    params[OUTLET_KEY]
  ].join(SCREEN_INSTANCE_DELIMITER);
  // eslint-disable-next-line no-prototype-builtins
  if (knownScreenInstanceIDs.hasOwnProperty(screenInstanceKey)) {
    return knownScreenInstanceIDs[screenInstanceKey];
  } else {
    const ret = nextScreenInstanceID++;
    knownScreenInstanceIDs[screenInstanceKey] = ret;
    return ret;
  }
};
